import sqlite3

def check_permission(user, file):
    # Connect to the database and query the user's access level
    conn = sqlite3.connect('permissions.db')
    c = conn.cursor()
    c.execute("SELECT access_level FROM users WHERE username=?", (user,))
    result = c.fetchone()

    # If the user has read permission, open and return the file contents
    if result[0] >= 1:
        with open(file, 'r') as f:
            return f.read()
    else:
        return None